const puppeteer = require('puppeteer');

(async () => {
  let browser;
  try {
    browser = await puppeteer.launch({
      args: ['--no-sandbox', '--disable-setuid-sandbox']
    });
    const page = await browser.newPage();

    console.log('Navigating to http://localhost:3000...');
    await page.goto('http://localhost:3000', { waitUntil: 'networkidle2', timeout: 30000 });

    console.log('Waiting for 2 seconds...');
    await new Promise(r => setTimeout(r, 2000));

    console.log('Checking for #chat-output...');
    const chatOutput = await page.$('#chat-output');

    if (!chatOutput) {
      console.log('RESULT: div with id "chat-output" not found.');
      await browser.close();
      return;
    }

    const textContent = await page.evaluate(el => el.textContent, chatOutput);
    console.log(`RESULT: Found #chat-output with content: "${textContent}"`);

    if (textContent === 'Hello streaming world') {
      console.log('VERIFICATION: SUCCESS');
    } else {
      console.log('VERIFICATION: FAILURE');
    }

  } catch (error) {
    console.error('ERROR:', error);
  } finally {
    if (browser) await browser.close();
  }
})();

